long long solve(vector<long long> nums, long long k) {
    int n = nums.size();
    if (n == 0) return 0;
    sort(nums.begin(), nums.end());
    long long max_len = 1;
    for (int i = 0; i < n; ++i) {
        long long target = nums[i] * k;
        int low = i;
        int high = n - 1;
        int best = i;
        while (low <= high) {
            int mid = (low + high) / 2;
            if (nums[mid] <= target) {
                best = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        int len = best - i + 1;
        if (len > max_len) {
            max_len = len;
        }
    }
    return n - max_len;
}

