			 best = mid
			 low = mid + 1
		 } else {
			 high = mid - 1
		 }
	 }
	 currentLen := best - i + 1
	 if currentLen > maxLen {
		 maxLen = currentLen
	 }
	}
	return int64(n - maxLen)
}
