import (
	"sort"
)

func solve(nums []int64, k int64) int64 {
	n := len(nums)
	if n == 0 {
		return 0
	}
	sort.Slice(nums, func(i, j int) bool { return nums[i] < nums[j] })
	maxLen := 1
	for i := 0; i < n; i++ {
		target := nums[i] * k
		index := sort.Search(n-i, func(j int) bool {
			return nums[i+j] > target
		})
		if index > maxLen {
			maxLen = index
		}
	}
	return int64(n - maxLen)
}
